import{_ as a,o as l,c as r,a0 as i}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Sync Players from the Game API","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/player-sync.md","filePath":"how-to/player-sync.md"}'),t={name:"how-to/player-sync.md"};function n(o,e,s,h,c,d){return l(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="sync-players-from-the-game-api" tabindex="-1">Sync Players from the Game API <a class="header-anchor" href="#sync-players-from-the-game-api" aria-label="Permalink to &quot;Sync Players from the Game API&quot;">​</a></h1><p>Player sync is an optional helper that fills or refreshes player details from the Kingshot game API. It is useful, but it is environment-dependent: some installations have it fully configured, and some do not.</p><h2 id="important-limitation" tabindex="-1">Important limitation <a class="header-anchor" href="#important-limitation" aria-label="Permalink to &quot;Important limitation&quot;">​</a></h2><p>If your environment does not have the Kingshot API client configured, or if the external service is unavailable, sync may fail or be unavailable. Manual player management still works either way.</p><h2 id="what-sync-can-update" tabindex="-1">What sync can update <a class="header-anchor" href="#what-sync-can-update" aria-label="Permalink to &quot;What sync can update&quot;">​</a></h2><p>When sync works, it can refresh fields such as:</p><ul><li>player name</li><li>profile ID link</li><li>avatar</li><li>kingdom reference</li><li>level</li><li>detailed level display</li><li>power</li><li>game rank</li><li>TC level</li></ul><h2 id="sync-while-creating-or-editing" tabindex="-1">Sync while creating or editing <a class="header-anchor" href="#sync-while-creating-or-editing" aria-label="Permalink to &quot;Sync while creating or editing&quot;">​</a></h2><p>From the player form:</p><ol><li>Enter a <strong>Kingshot profile ID</strong>.</li><li>Select <strong>Sync</strong>.</li><li>Review the filled fields.</li><li>Save the player.</li></ol><p>If no data comes back, you can still save the player manually.</p><h2 id="sync-an-existing-player-from-the-directory" tabindex="-1">Sync an existing player from the directory <a class="header-anchor" href="#sync-an-existing-player-from-the-directory" aria-label="Permalink to &quot;Sync an existing player from the directory&quot;">​</a></h2><p>In the <strong>Players</strong> list, linked players can show a sync action on their row. Use it when you want to refresh the stored profile.</p><p>The row may show states such as:</p><ul><li><code>sync pending</code></li><li><code>API syncing</code></li><li><code>API synced now</code></li><li><code>API sync failed</code></li><li><code>synced ...</code></li></ul><h2 id="sync-from-the-full-profile" tabindex="-1">Sync from the full profile <a class="header-anchor" href="#sync-from-the-full-profile" aria-label="Permalink to &quot;Sync from the full profile&quot;">​</a></h2><p>The player profile also has a <strong>Sync</strong> action in <strong>Profile Foundation</strong>. This is helpful when you want to review the incoming changes before saving them.</p><h2 id="background-refresh-behavior" tabindex="-1">Background refresh behavior <a class="header-anchor" href="#background-refresh-behavior" aria-label="Permalink to &quot;Background refresh behavior&quot;">​</a></h2><p>The app can also queue background refresh jobs for players with profile IDs. In normal day-to-day use, you mostly notice this through changing sync labels and fresher player fields rather than through a separate queue screen.</p><h2 id="when-sync-will-not-work" tabindex="-1">When sync will not work <a class="header-anchor" href="#when-sync-will-not-work" aria-label="Permalink to &quot;When sync will not work&quot;">​</a></h2><ul><li>the player has no Kingshot profile ID</li><li>the environment is not configured for API sync</li><li>the external API is temporarily failing</li></ul><p>In those cases, keep working manually and try again later if needed.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./add-player.html">Add a Player</a></li><li><a href="./edit-player.html">Edit Player Details</a></li><li><a href="./player-profile.html">Read a Player Profile</a></li><li><a href="./players-directory.html">Browse &amp; Filter Players</a></li></ul>',24)])])}const f=a(t,[["render",n]]);export{p as __pageData,f as default};
